// --- HELPERS ---
function mapsUrl(address) {
  return `https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(address)}`;
}
function phoneUrl(phone) {
  return `tel:${phone.replace(/[\s\-()]/g, "")}`;
}
function waUrl(phone) {
  const clean = phone.replace(/[\s\-()]/g, "").replace("+", "");
  return `https://wa.me/${clean}`;
}
function getJapanTime() {
  const now = new Date();
  return now.toLocaleString("en-US", { timeZone: "Asia/Tokyo", hour: "numeric", minute: "2-digit", hour12: true, weekday: "short" });
}
function getBuenosAiresTime() {
  const now = new Date();
  return now.toLocaleString("en-US", { timeZone: "America/Argentina/Buenos_Aires", hour: "numeric", minute: "2-digit", hour12: true, weekday: "short" });
}

// --- COMPONENTS ---
function PhoneButton({ phone, noWhatsApp }) {
  return (
    <div style={{ display: "flex", gap: 8, marginTop: 6 }}>
      <a href={phoneUrl(phone)} style={styles.phonePill}>📞 Call</a>
      {!noWhatsApp && <a href={waUrl(phone)} target="_blank" rel="noopener noreferrer" style={{ ...styles.phonePill, background: "#25D366", color: "#fff" }}>💬 WhatsApp</a>}
    </div>
  );
}

function AddressLink({ address, mapsLink }) {
  const [copied, setCopied] = useState(false);
  const handleCopy = (e) => {
    e.preventDefault();
    navigator.clipboard.writeText(address).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    });
  };
  const link = mapsLink || mapsUrl(address);
  return (
    <div style={{ marginTop: 6 }}>
      <a href={link} target="_blank" rel="noopener noreferrer" style={styles.addressLink}>
        📍 {address}
      </a>
      <button onClick={handleCopy} style={styles.copyPill}>
        {copied ? "✓ Copied!" : "📋 Copy for Uber"}
      </button>
    </div>
  );
}

function Card({ children, style: extraStyle, accent }) {
  return (
    <div style={{ ...styles.card, ...extraStyle, borderLeft: accent ? `4px solid ${accent}` : undefined }}>
      {children}
    </div>
  );
}

function Section({ title, icon, children, defaultOpen = false, accent = "#1e3a5f", count }) {
  const [open, setOpen] = useState(defaultOpen);
  return (
    <div style={{ marginBottom: 4 }}>
      <button onClick={() => setOpen(!open)} style={styles.sectionBtn}>
        <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
          {icon && <span style={{ fontSize: 20 }}>{icon}</span>}
          <span style={{ fontSize: 16, fontWeight: 700, color: "#1e3a5f" }}>{title}</span>
          {count != null && <span style={{ fontSize: 12, background: "#e8f0fe", color: "#1e40af", borderRadius: 10, padding: "1px 8px", fontWeight: 600 }}>{count}</span>}
        </div>
        <span style={{
          fontSize: 20,
          color: "#9ca3af",
          transition: "transform 0.25s ease",
          transform: open ? "rotate(180deg)" : "rotate(0deg)",
          lineHeight: 1,
        }}>⌄</span>
      </button>
      <div style={{
        maxHeight: open ? 5000 : 0,
        overflow: "hidden",
        transition: "max-height 0.35s ease",
      }}>
        <div style={{ paddingTop: 4 }}>{children}</div>
      </div>
    </div>
  );
}

function Collapsible({ title, children, defaultOpen = false, accent }) {
  const [open, setOpen] = useState(defaultOpen);
  return (
    <div style={{ marginBottom: 12 }}>
      <button onClick={() => setOpen(!open)} style={{ ...styles.collapsibleHeader, borderLeft: accent ? `4px solid ${accent}` : "4px solid #d1d5db" }}>
        <span>{title}</span>
        <span style={{ fontSize: 18, transition: "transform 0.2s", transform: open ? "rotate(90deg)" : "rotate(0deg)" }}>›</span>
      </button>
      {open && <div style={styles.collapsibleBody}>{children}</div>}
    </div>
  );
}

